import './WordGallery.scss';

import { Card } from ':components/Card';
import type { WordFile } from ':components/Preview/Preview.types';
import React, { useEffect, useRef, useState } from 'react';

export interface WordGalleryProps {
	selectedIndex: number;
	onClick: (index: number) => void;
	value: WordFile;
}

interface PageData {
	index: number;
	html: string;
	styles: string;
}

export const WordGallery: React.FC<WordGalleryProps> = ({ selectedIndex, onClick, value }) => {
	const [pages, setPages] = useState<PageData[]>([]);
	const [isLoaded, setIsLoaded] = useState(false);
	const galleryRef = useRef<HTMLDivElement>(null);
	const hiddenContainerRef = useRef<HTMLDivElement>(null);

	const scrollToSelected = (index: number) => {
		if (galleryRef.current) {
			const cards = galleryRef.current.querySelectorAll('.dsb_preview__gallery-word__frame');
			if (cards[index]) {
				const card = cards[index] as HTMLElement;
				const container = galleryRef.current;
				const cardTop = card.offsetTop;
				const cardHeight = card.offsetHeight;
				const containerHeight = container.offsetHeight;

				container.scrollTo({
					top: cardTop - containerHeight / 2 + cardHeight / 2,
					behavior: 'smooth',
				});
			}
		}
	};

	useEffect(() => {
		scrollToSelected(selectedIndex);
	}, [selectedIndex, isLoaded]);

	useEffect(() => {
		let isMounted = true;
		let abortController: AbortController | null = null;

		const loadDocument = async () => {
			if (!hiddenContainerRef.current) return;

			setIsLoaded(false);
			setPages([]);

			try {
				abortController = new AbortController();
				const response = await fetch(value.src, { signal: abortController.signal });

				if (!response.ok) {
					throw new Error(`Ошибка загрузки: ${response.statusText}`);
				}

				const arrayBuffer = await response.arrayBuffer();

				if (!isMounted || !hiddenContainerRef.current) return;

				hiddenContainerRef.current.innerHTML = '';

				const docxPreview = await import('docx-preview');
				const renderFunction = docxPreview.renderDocument || docxPreview.default?.renderDocument;

				if (typeof renderFunction !== 'function') return;

				const parsedDocument = await docxPreview.parseAsync(arrayBuffer);
				await renderFunction(parsedDocument, hiddenContainerRef.current, undefined, {
					className: 'dsb_gallery_word_thumb',
					inWrapper: true,
					ignoreWidth: false,
					ignoreHeight: false,
					ignoreFonts: false,
					breakPages: true,
					experimental: false,
				});

				if (!isMounted || !hiddenContainerRef.current) return;

				await new Promise(resolve => requestAnimationFrame(resolve));

				// Собираем стили из документа
				const styleElements = hiddenContainerRef.current.querySelectorAll('style');
				const styles = Array.from(styleElements)
					.map(el => el.outerHTML)
					.join('\n');

				const pageElements = hiddenContainerRef.current.querySelectorAll('section.dsb_gallery_word_thumb');

				const pagesData: PageData[] = Array.from(pageElements).map((page, index) => ({
					index,
					html: page.outerHTML,
					styles,
				}));

				setPages(pagesData);
				setIsLoaded(true);
			} catch (err) {
				if (err instanceof Error && err.name !== 'AbortError' && isMounted) {
					console.error('WordGallery: ошибка загрузки документа', err);
				}
			}
		};

		void loadDocument();

		return () => {
			isMounted = false;
			abortController?.abort();
		};
	}, [value.src]);

	return (
		<div className="dsb_preview__gallery-word" ref={galleryRef}>
			{/* Скрытый контейнер для рендеринга документа */}
			<div ref={hiddenContainerRef} className="dsb_preview__gallery-word__hidden-container" />

			{isLoaded &&
				pages.map(page => (
					<div key={`page-wrapper_${page.index}`} className="dsb_preview__gallery-word__item">
						<Card
							border={page.index === selectedIndex ? 'brand' : 'default'}
							elevation="medium"
							className="dsb_preview__gallery-word__frame"
							onClick={() => onClick(page.index)}
						>
							<div
								className="dsb_preview__gallery-word__frame__page"
								dangerouslySetInnerHTML={{ __html: page.styles + page.html }}
							/>
						</Card>
						<p className="dsb_preview__gallery-word__caption">{page.index + 1}</p>
					</div>
				))}
		</div>
	);
};
